+            "blocks" => Self::Blocks,
+            "parent-child" => Self::ParentChild,
+            "conditional-blocks" => Self::ConditionalBlocks,
+            "waits-for" => Self::WaitsFor,
+            "related" => Self::Related,
+            "discovered-from" => Self::DiscoveredFrom,
+            "replies-to" => Self::RepliesTo,
